alter table if exists missao
    add column if not exists value integer not null default 0;

alter table if exists missao
    drop constraint if exists missao_value_check;

alter table if exists missao
    add constraint missao_value_check
    check (value >= 0);

update missao
set value = v.value
from (
    values
    ('10000000-0000-0000-0000-000000000001'::uuid, 20),
