    ('10000000-0000-0000-0000-000000000011'::uuid, 20),
    ('10000000-0000-0000-0000-000000000012'::uuid, 40),
    ('10000000-0000-0000-0000-000000000013'::uuid, 15),
    ('10000000-0000-0000-0000-000000000014'::uuid, 15),
    ('10000000-0000-0000-0000-000000000015'::uuid, 20),
